#include <stdio.h>
#include <stdlib.h>
#include <limits.h>

// Define the structure for a tree node
typedef struct Node {
    int val;
    struct Node *left;
    struct Node *right;
} Node;

// Function to create a new node
Node* newNode(int val) {
    Node* node = (Node*)malloc(sizeof(Node));
    node->val = val;
    node->left = node->right = NULL;
    return node;
}

// Function to check if a tree is a BST
int isBST(Node* root, int min, int max) {
    if (root == NULL) return 1;
    if (root->val <= min || root->val >= max) return 0;
    return isBST(root->left, min, root->val) && isBST(root->right, root->val, max);
}

int main() {
    int N;
    scanf("%d", &N);
    Node* root = NULL;
    for (int i = 0; i < N - 1; i++) {
        int pi, ci;
        char Ri;
        scanf("%d %d %c", &pi, &ci, &Ri);
        // Create nodes and assign them based on the input
        if (root == NULL) {
            root = newNode(pi);
            if (Ri == 'L') {
                root->left = newNode(ci);
            } else {
                root->right = newNode(ci);
            }
