    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        Node root = null;
        for (int i = 0; i < N - 1; i++) {
            int pi = sc.nextInt();
            int ci = sc.nextInt();
            char Ri = sc.next().charAt(0);
            // Create nodes and assign them based on the input
            if (root == null) {
                root = new Node(pi);
                if (Ri == 'L') {
                    root.left = new Node(ci);
                } else {
                    root.right = new Node(ci);
                }
            } else {
                Node curr = root;
                while (true) {
                    if (pi == curr.val) {
                        if (Ri == 'L') {
                            curr.left = new Node(ci);
                        } else {
                            curr.right = new Node(ci);
                        }
                        break;
                    } else if (pi < curr.val) {
                        if (curr.left == null) {
                            curr.left = new Node(pi);
                            if (Ri == 'L') {
                                curr.left.left = new Node(ci);
                            } else {
                                curr.left.right = new Node(ci);
                            }
                            break;
                        }
                        curr = curr.left;
