                            }
                            break;
                        }
                        curr = curr.right;
                    }
                }
            }
        }
        if (isBST(root, Integer.MIN_VALUE, Integer.MAX_VALUE)) System.out.println("YES");
        else System.out.println("NO");
    }
}

